import React, { useState, useEffect } from 'react';
import { Camera, Image as ImageIcon, Video, Mail, Phone, MapPin, Menu, X, ChevronRight, Globe, Maximize2, MessageCircle, CheckCircle2 } from 'lucide-react';

// Custom Instagram Icon
const InstagramIcon = ({ className }) => (
  <svg 
    viewBox="0 0 24 24" 
    fill="none" 
    stroke="currentColor" 
    strokeWidth="2" 
    strokeLinecap="round" 
    strokeLinejoin="round" 
    className={className}
  >
    <rect x="2" y="2" width="20" height="20" rx="5" ry="5"></rect>
    <path d="M16 11.37A4 4 0 1 1 12.63 8 4 4 0 0 1 16 11.37z"></path>
    <line x1="17.5" y1="6.5" x2="17.51" y2="6.5"></line>
  </svg>
);

const App = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [lang, setLang] = useState('ar');
  const [selectedGallery, setSelectedGallery] = useState(null);

  // State lal Form (Metel ma kinto)
  const [formData, setFormData] = useState({ name: '', email: '', message: '' });

  // --- EL-SER KERMEL EL-SUWAR (MA B-GHAYYER EL-CONTENT) ---
  const imgPath = (path) => process.env.PUBLIC_URL + path;

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const content = {
    en: {
      nav: ['Services', 'Portfolio', 'Contact'],
      hero: {
        title: 'Capturing Moments, Telling Stories',
        subtitle: 'Professional photography and video production for your most precious memories.',
        cta: 'Book a Session'
      },
      services: {
        title: 'Our Services',
        items: [
          { title: 'Commercial', desc: 'High-end product and brand photography.', icon: <Camera />, img: imgPath('/img/service1.jpg') },
          { title: 'Events', desc: 'Coverage for weddings, parties, and corporate events.', icon: <ImageIcon />, img: imgPath('/img/service2.jpg') },
          { title: 'Video Production', desc: 'Cinematic storytelling for any occasion.', icon: <Video />, img: imgPath('/img/service3.jpg') }
        ]
      },
      portfolio: {
        title: 'Our Portfolio',
        categories: ['All', 'Commercial', 'Events', 'Video'],
        items: [
          { id: 1, category: 'Commercial', title: 'Product Shoot', img: imgPath('/img/p1.jpg') },
          { id: 2, category: 'Events', title: 'Wedding Day', img: imgPath('/img/p2.jpg') },
          { id: 3, category: 'Video', title: 'Brand Story', img: imgPath('/img/p3.jpg') },
          { id: 4, category: 'Commercial', title: 'Fashion', img: imgPath('/img/p4.jpg') },
          { id: 5, category: 'Events', title: 'Gala Dinner', img: imgPath('/img/p5.jpg') },
          { id: 6, category: 'Video', title: 'Music Video', img: imgPath('/img/p6.jpg') }
        ]
      },
      contact: {
        title: 'Get In Touch',
        subtitle: "Let's discuss your next project",
        info: [
          { icon: <Phone />, text: '+961 70 000 000', label: 'Phone' },
          { icon: <Mail />, text: 'info@circle.com', label: 'Email' },
          { icon: <MapPin />, text: 'Tripoli, Lebanon', label: 'Studio' }
        ],
        placeholder: { name: 'Name', email: 'Email', message: 'Message', send: 'Send Message' }
      },
      whatsappBtn: 'Contact via WhatsApp',
      instagramBtn: 'Follow on Instagram'
    },
    ar: {
      nav: ['خدماتنا', 'أعمالنا', 'اتصل بنا'],
      hero: {
        title: 'نخلد اللحظات.. لنروي القصص',
        subtitle: 'تصوير احترافي وإنتاج فيديو لأثمن ذكرياتكم بأعلى جودة.',
        cta: 'احجز جلستك الآن'
      },
      services: {
        title: 'خدماتنا',
        items: [
          { title: 'التصوير التجاري', desc: 'تصوير المنتجات والعلامات التجارية باحترافية.', icon: <Camera />, img: imgPath('/img/service1.jpg') },
          { title: 'المناسبات', desc: 'تغطية كاملة للأعراس، الحفلات والمناسبات الخاصة.', icon: <ImageIcon />, img: imgPath('/img/service2.jpg') },
          { title: 'إنتاج الفيديو', desc: 'صناعة محتوى مرئي يحكي قصتكم بأسلوب سينمائي.', icon: <Video />, img: imgPath('/img/service3.jpg') }
        ]
      },
      portfolio: {
        title: 'أعمالنا',
        categories: ['الكل', 'تجاري', 'مناسبات', 'فيديو'],
        items: [
          { id: 1, category: 'تجari', title: 'جلسة تصوير منتجات', img: imgPath('/img/p1.jpg') },
          { id: 2, category: 'مناسبات', title: 'يوم الزفاف', img: imgPath('/img/p2.jpg') },
          { id: 3, category: 'فيديو', title: 'قصة علامة تجارية', img: imgPath('/img/p3.jpg') },
          { id: 4, category: 'تجari', title: 'أزياء', img: imgPath('/img/p4.jpg') },
          { id: 5, category: 'مناسبات', title: 'عشاء فاخر', img: imgPath('/img/p5.jpg') },
          { id: 6, category: 'فيديو', title: 'فيديو موسيقي', img: imgPath('/img/p6.jpg') }
        ]
      },
      contact: {
        title: 'تواصل معنا',
        subtitle: 'دعنا نناقش مشروعك القادم',
        info: [
          { icon: <Phone />, text: '+961 70 000 000', label: 'هاتف' },
          { icon: <Mail />, text: 'info@circle.com', label: 'بريد إلكتروني' },
          { icon: <MapPin />, text: 'طرابلس، لبنان', label: 'الاستوديو' }
        ],
        placeholder: { name: 'الاسم', email: 'البريد الإلكتروني', message: 'الرسالة', send: 'إرسال الرسالة' }
      },
      whatsappBtn: 'تواصل عبر واتساب',
      instagramBtn: 'تابعنا على إنستغرام'
    }
  };

  return (
    <div className={`min-h-screen bg-[#0a0a0a] text-white font-sans ${lang === 'ar' ? 'rtl' : 'ltr'}`}>
      {/* Navbar */}
      <nav className={`fixed w-full z-50 transition-all duration-500 ${isScrolled ? 'bg-[#0a0a0a]/90 backdrop-blur-xl py-4 shadow-2xl' : 'bg-transparent py-8'}`}>
        <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-gradient-to-tr from-pink-500 to-violet-500 rounded-full flex items-center justify-center p-0.5">
              <div className="w-full h-full bg-black rounded-full flex items-center justify-center">
                <Camera className="w-6 h-6 text-white" />
              </div>
            </div>
            <span className="text-2xl font-black tracking-tighter uppercase italic">Circle</span>
          </div>

          <div className="hidden md:flex items-center gap-12">
            {content[lang].nav.map((item, index) => (
              <a key={index} href={`#${item.toLowerCase()}`} className="text-sm font-bold uppercase tracking-[0.2em] hover:text-pink-500 transition-colors duration-300">
                {item}
              </a>
            ))}
            <button 
              onClick={() => setLang(lang === 'ar' ? 'en' : 'ar')}
              className="flex items-center gap-2 px-4 py-2 rounded-full border border-white/10 hover:bg-white/5 transition-all"
            >
              <Globe className="w-4 h-4" />
              <span className="text-xs font-bold uppercase tracking-widest">{lang === 'ar' ? 'EN' : 'AR'}</span>
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section id="home" className="relative h-screen flex items-center justify-center overflow-hidden">
        <div className="absolute inset-0 z-0">
          <img 
            src={imgPath('/img/hero.jpg')} 
            alt="Hero Background" 
            className="w-full h-full object-cover opacity-50 scale-105 animate-slow-zoom"
          />
          <div className="absolute inset-0 bg-gradient-to-b from-[#0a0a0a]/50 via-transparent to-[#0a0a0a]" />
        </div>
        <div className="relative z-10 text-center px-6 max-w-4xl">
          <h1 className="text-6xl md:text-9xl font-black mb-8 tracking-tighter leading-none uppercase italic italic-gradient">
            {content[lang].hero.title}
          </h1>
          <p className="text-lg md:text-2xl text-gray-400 mb-12 max-w-2xl mx-auto font-light tracking-wide leading-relaxed">
            {content[lang].hero.subtitle}
          </p>
          <button className="group relative px-12 py-5 bg-white text-black font-black uppercase tracking-widest overflow-hidden transition-all duration-300 hover:scale-105 rounded-full">
            <span className="relative z-10">{content[lang].hero.cta}</span>
          </button>
        </div>
      </section>

      {/* Services Section */}
      <section id="services" className="py-32 px-6 bg-[#0d0d0d]">
        <div className="max-w-7xl mx-auto">
          <h2 className="text-5xl md:text-7xl font-black mb-24 tracking-tighter uppercase italic">{content[lang].services.title}</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-12">
            {content[lang].services.items.map((service, index) => (
              <div key={index} className="group relative bg-[#141414] rounded-3xl overflow-hidden border border-white/5 hover:border-pink-500/30 transition-all duration-500">
                <div className="aspect-[4/5] overflow-hidden">
                  <img src={service.img} alt={service.title} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110 opacity-70 group-hover:opacity-100" />
                </div>
                <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-transparent p-10 flex flex-col justify-end translate-y-8 group-hover:translate-y-0 transition-transform duration-500">
                  <div className="w-14 h-14 bg-white/10 backdrop-blur-xl rounded-2xl flex items-center justify-center mb-6">
                    {service.icon}
                  </div>
                  <h3 className="text-3xl font-bold mb-4 uppercase italic tracking-tighter">{service.title}</h3>
                  <p className="text-gray-400 font-light leading-relaxed opacity-0 group-hover:opacity-100 transition-opacity duration-500 delay-100">{service.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Portfolio Section */}
      <section id="portfolio" className="py-32 px-6 bg-black">
        <div className="max-w-7xl mx-auto">
          <div className="flex flex-col md:flex-row justify-between items-end gap-8 mb-24">
            <h2 className="text-5xl md:text-7xl font-black tracking-tighter uppercase italic">{content[lang].portfolio.title}</h2>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {content[lang].portfolio.items.map((item) => (
              <div key={item.id} className="group relative aspect-square overflow-hidden rounded-3xl bg-[#141414] cursor-pointer" onClick={() => setSelectedGallery(item)}>
                <img src={item.img} alt={item.title} className="w-full h-full object-cover transition-all duration-700 group-hover:scale-110 group-hover:rotate-1 opacity-80 group-hover:opacity-100" />
                <div className="absolute inset-0 bg-pink-500/20 opacity-0 group-hover:opacity-100 transition-opacity duration-500" />
                <div className="absolute bottom-8 left-8 right-8 translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-500">
                  <span className="text-xs font-black uppercase tracking-[0.3em] text-pink-500 mb-2 block">{item.category}</span>
                  <h3 className="text-2xl font-bold uppercase italic">{item.title}</h3>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Contact Section */}
      <section id="contact" className="py-32 px-6 bg-[#0d0d0d]">
        <div className="max-w-7xl mx-auto text-center">
          <h2 className="text-5xl md:text-8xl font-black mb-8 tracking-tighter uppercase italic">{content[lang].contact.title}</h2>
          <p className="text-xl text-gray-500 mb-20 uppercase tracking-widest font-light">{content[lang].contact.subtitle}</p>

          <div className="flex flex-col sm:flex-row justify-center items-center gap-6">
            <a href="https://wa.me/96170000000" target="_blank" rel="noopener noreferrer" className="group border border-white/10 hover:border-green-500/50 bg-white/5 p-8 rounded-2xl transition-all duration-300 w-full max-w-xs flex flex-col items-center">
              <MessageCircle className="w-12 h-12 text-[#25D366] mb-4 group-hover:scale-110 transition-transform" />
              <span className="text-lg font-bold uppercase tracking-widest">{content[lang].whatsappBtn}</span>
            </a>
            <a href="https://instagram.com/circle_advertising" target="_blank" rel="noopener noreferrer" className="group border border-white/10 hover:border-pink-500/50 bg-white/5 p-8 rounded-2xl transition-all duration-300 w-full max-w-xs flex flex-col items-center">
              <InstagramIcon className="w-12 h-12 text-pink-500 mb-4 group-hover:scale-110 transition-transform" />
              <span className="text-lg font-bold uppercase tracking-widest">{content[lang].instagramBtn}</span>
            </a>
          </div>
        </div>
      </section>

      <footer className="py-12 px-6 border-t border-white/5 text-center">
        <p className="text-gray-600 text-xs font-bold uppercase tracking-[0.5em]">© 2024 Circle Advertising. All Rights Reserved.</p>
      </footer>
    </div>
  );
};

export default App;
